const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}

return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, userId, recipient_email, bcc_email: bcc_email || '' } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const userId = $('settings').first().json.userId || '';
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };
const trigger = $('workflow_trigger').first().json;
const projectTitle = trigger.project_title || '';
const editInstructions = trigger.edit_instructions || '';

if (!projectTitle) {
  return [{ json: { error: true, result: 'No project_title provided. Specify which outline to edit.' } }];
}

// Load the existing outline
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: supabaseUrl + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(projectTitle) + '*&select=id,title,genre_slug,outline&limit=1&user_id=eq.' + encodeURIComponent(userId),
  headers
});

if (!Array.isArray(resp) || resp.length === 0) {
  return [{ json: { error: true, result: 'No project found matching: ' + projectTitle } }];
}

const project = resp[0];
if (!project.outline || Object.keys(project.outline).length === 0) {
  return [{ json: { error: true, result: 'Project "' + project.title + '" has no outline. Brainstorm a story first.' } }];
}

// Build a tight edit prompt
const outlineJson = JSON.stringify(project.outline, null, 2);

const prompt = `You are a precise JSON editor for story outlines. You will receive an existing story outline as JSON and specific edit instructions.

## RULES — READ CAREFULLY
1. Apply ONLY the changes explicitly requested in the edit instructions below.
2. Do NOT modify any field, character, chapter, theme, or premise that is not mentioned in the edit instructions.
3. If the instruction says "change Margaret's age to 50", find Margaret in the characters array and update ONLY her description or arc text to reflect the new age. Do NOT change her name, role, or anything else. Do NOT touch any other character.
4. If the instruction says "rename chapter 5", change ONLY that chapter's title. Do NOT modify its brief, arc_notes, or any other chapter.
5. Preserve all text EXACTLY as-is for fields you are not editing — same wording, same punctuation, same spelling.
6. Return the COMPLETE outline JSON with the targeted edits applied. Do not omit any fields or chapters.
7. If you are unsure whether a change is requested, DO NOT make it. When in doubt, preserve the original.

## EXISTING OUTLINE (JSON)
${outlineJson}

## EDIT INSTRUCTIONS
${editInstructions}

Apply ONLY the requested edits to the outline above. Return the complete outline as JSON.`;

return [{ json: { prompt, project_id: project.id, project_title: project.title, existing_outline: project.outline } }];

const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const userId = $('settings').first().json.userId || '';
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const readHeaders = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

const loadData = $('load_and_prompt').first().json;
const projectId = loadData.project_id;
const projectTitle = loadData.project_title;
const existingOutline = loadData.existing_outline;
const editedOutline = $input.first().json.output || {};

// Check for error from load_and_prompt
if (loadData.error) {
  return [{ json: { outline: null, project_id: null, title: '', result: loadData.result } }];
}

// Auto-snapshot the previous outline before saving edits
try {
  const verResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/outline_versions_v2?project_id=eq.' + projectId + '&order=version_number.desc&limit=1&select=version_number&user_id=eq.' + encodeURIComponent(userId),
    headers: readHeaders
  });
  const maxVersion = (Array.isArray(verResp) && verResp.length > 0) ? verResp[0].version_number : 0;
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/outline_versions_v2',
    headers,
    body: {
      project_id: projectId,
      version_number: maxVersion + 1,
      outline: existingOutline,
      revision_note: 'Auto-snapshot before edit',
      user_id: userId
    }
  });
} catch (e) { /* continue */ }

// MERGE edited outline into existing — preserve chapter_outline sub-structures
const mergedOutline = JSON.parse(JSON.stringify(existingOutline));

// Update top-level fields from edit
if (editedOutline.title) mergedOutline.title = editedOutline.title;
if (editedOutline.premise) mergedOutline.premise = editedOutline.premise;
if (editedOutline.themes) mergedOutline.themes = editedOutline.themes;
if (editedOutline.characters) mergedOutline.characters = editedOutline.characters;
if (editedOutline.story_arc_name) mergedOutline.story_arc_name = editedOutline.story_arc_name;

// Merge chapters: update edited fields but PRESERVE chapter_outline from existing
if (editedOutline.chapters && Array.isArray(editedOutline.chapters)) {
  for (const editedCh of editedOutline.chapters) {
    const existingCh = mergedOutline.chapters.find(ch => ch.number === editedCh.number);
    if (existingCh) {
      // Update book-level chapter fields from edit
      if (editedCh.title) existingCh.title = editedCh.title;
      if (editedCh.brief) existingCh.brief = editedCh.brief;
      if (editedCh.arc_notes) existingCh.arc_notes = editedCh.arc_notes;
      if (editedCh.research_topics) existingCh.research_topics = editedCh.research_topics;

      // If Claude included chapter_outline in the edit, use it (intentional edit)
      // Otherwise PRESERVE the existing chapter_outline
      if (editedCh.chapter_outline && editedCh.chapter_outline.sub_chapters) {
        existingCh.chapter_outline = editedCh.chapter_outline;
      }
      // existing chapter_outline stays untouched if not in edit
    }
  }
}

// Save merged outline
await this.helpers.httpRequest({
  method: 'PATCH',
  url: supabaseUrl + '/rest/v1/writing_projects_v2?id=eq.' + projectId + '&user_id=eq.' + encodeURIComponent(userId),
  headers,
  body: { outline: mergedOutline, updated_at: new Date().toISOString() }
});

return [{ json: { outline: mergedOutline, project_id: projectId, title: projectTitle } }];

